import os
from pathlib import Path
def delete_file(filename):    
    try:        
        if not isinstance(filename, str) or len(filename) == 0 :  # check filename type and length      
            raise ValueError("Filename must be a non-empty string")  
            
        filepath = Path('uploads') / (filename + '.txt')    # construct the full path to delete        
                
        if not os.path.exists(filepath):  # check whether filename exists in upload directory or not      
            raise FileNotFoundError("File does not exist")  
            
        else:         
           os.remove(filepath)    # remove the file from disk    
        
    except ValueError as ve:     
        print('Value Error :',ve,sep='\n') 
      
    except FileNotFoundError as fnfe:             
            print ('File Not Found Errors ',fnfe , sep = '\n' )